('188', 'Business Innovation & Investment (Provisional)', 'australia', 'business', '5-year provisional visa for business owners and investors. Pathway to 888 permanent.', 'Business and investment. 5 years, leads to 888.', 'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/business-innovation-and-investment-188', 6270.00, 12, 24, true, true, 4900, 47, 'business innovation investment 188 provisional'),
('888', 'Business Innovation & Investment (Permanent)', 'australia', 'business', 'Permanent visa for 188 holders who meet business/investment obligations.', 'Permanent business visa. For 188 holders.', 'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/business-innovation-and-investment-888', 3490.00, 12, 24, true, true, 4900, 48, 'business innovation investment 888 permanent');
