('866', 'Protection Visa', 'australia', 'humanitarian', 'Permanent visa for people seeking asylum in Australia. Onshore protection.', 'Asylum seeker visa. Onshore protection claim.', 'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/protection-866', 0.00, 6, 36, true, true, 4900, 49, 'protection visa 866 asylum refugee');
