-- Migration: Seed Tier 2-5 Australian Visas (73 additional visas)
-- Tracks: 003, 004, 005, 006
-- Status: IN_PROGRESS
-- DHA Base URL: https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/

-- TIER 2: Important Visas (8 visas)

-- TIER 3: Parent & Family Visas (8 visas)

-- TIER 4: More Family & Other Visas (12 visas)

-- TIER 5: Visitor & Short Stay (6 visas)

-- TIER 6: Bridging Visas (7 visas)

-- TIER 7: Business & Investment (2 visas)

-- TIER 8: Humanitarian (2 visas)

-- Verify all insertions
SELECT 
    COUNT(*) as total_visas,
    COUNT(*) FILTER (WHERE display_order <= 8) as tier_1,
    COUNT(*) FILTER (WHERE display_order > 8 AND display_order <= 16) as tier_2,
    COUNT(*) FILTER (WHERE display_order > 16 AND display_order <= 30) as family,
    COUNT(*) FILTER (WHERE display_order > 30 AND display_order <= 41) as other,
    COUNT(*) FILTER (WHERE display_order > 41) as bridging_humanitarian
FROM public.visas WHERE country = 'australia';
